### `model/use-first-use-date.ts`

New hook for first-use date tracking:

```typescript
import { useEffect, useState } from 'react';

const FIRST_USE_KEY = 'dorkos-first-use-date';

/**
 * Calculate the number of days between a date string and now.
 * Returns 0 if the date is invalid or in the future.
 */
export function daysSince(dateStr: string | null): number {
  if (!dateStr) return 0;
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return 0;
  const diff = Date.now() - date.getTime();
  return Math.max(0, Math.floor(diff / (1000 * 60 * 60 * 24)));
}

/**
 * Read/write a firstUseDate key in localStorage on first app load.
 * Returns the ISO date string of the first time the app was loaded.
 */
export function useFirstUseDate(): string | null {
  const [firstUseDate] = useState<string | null>(() => {
    try {
      const stored = localStorage.getItem(FIRST_USE_KEY);
      if (stored) return stored;
      const now = new Date().toISOString();
      localStorage.setItem(FIRST_USE_KEY, now);
      return now;
    } catch {
      return null;
    }
  });

  return firstUseDate;
}
```

