| `usePulseEnabled()` | `entities/pulse` | Confirmed: `use-pulse-config.ts` |
| `useRelayEnabled()` | `entities/relay` | Confirmed: `use-relay-config.ts` |
| `useSessions()` | `entities/session` | Confirmed: returns `{ sessions, ... }` |
| `useRelayAdapters()` | `entities/relay` | Confirmed: `use-relay-adapters.ts` — verify return shape |
| Mesh connection | `entities/mesh` | Check exports — may need adaptation |

## Acceptance Criteria

- `usePromoContext()` returns a correctly shaped `PromoContext` object
- `hasAdapter` correctly checks adapter type and connected status
- `daysSince` returns 0 for null/invalid dates, correct day count for valid dates
- `useFirstUseDate` writes to localStorage on first call, reads on subsequent calls
- All hooks follow FSD layer rules (only import from entities and shared)
- `pnpm typecheck` passes

Create the main consumer hook `usePromoSlot` that filters, sorts, and caps promos for a given placement slot. Include comprehensive tests.

## File: `model/use-promo-slot.ts`

```typescript
import { useMemo } from 'react';
import type { PromoDefinition, PromoPlacement } from './promo-types';
import { PROMO_REGISTRY } from './promo-registry';
import { usePromoContext } from './promo-context';
import { useAppStore } from '@/layers/shared/model';

/**
 * Main consumer hook — returns filtered, sorted, capped promos for a placement slot.
 *
 * Pipeline: filter by placement -> exclude dismissed -> evaluate conditions -> sort by priority desc -> cap at maxUnits.
 * Returns empty array when global toggle is off or no promos qualify.
 */
export function usePromoSlot(placement: PromoPlacement, maxUnits: number): PromoDefinition[] {
  const ctx = usePromoContext();
  const dismissedPromoIds = useAppStore((s) => s.dismissedPromoIds);
  const promoEnabled = useAppStore((s) => s.promoEnabled);

  return useMemo(() => {
    if (!promoEnabled) return [];

    return PROMO_REGISTRY
      .filter((p) => p.placements.includes(placement))
      .filter((p) => !dismissedPromoIds.includes(p.id))
      .filter((p) => p.shouldShow(ctx))
      .sort((a, b) => b.priority - a.priority)
      .slice(0, maxUnits);
  }, [placement, maxUnits, ctx, dismissedPromoIds, promoEnabled]);
}
```

