    expect(result.current).toEqual([]);
  });

  it('returns empty array when no promos qualify for a placement', () => {
    mockRegistry.push(
      makePromo({ id: 'a', placements: ['dashboard-sidebar'] }),
    );
    const { result } = renderHook(() => usePromoSlot('agent-sidebar', 10));
    expect(result.current).toEqual([]);
  });
});
```

## Acceptance Criteria

- Hook filters by placement, excludes dismissed, evaluates shouldShow, sorts by priority desc, caps at maxUnits
- Returns `[]` when `promoEnabled` is `false`
- Returns `[]` when no promos match the placement
- Pipeline order is correct: placement filter -> dismiss filter -> shouldShow -> sort -> slice
- All 7 test cases pass via `pnpm vitest run`
- `pnpm typecheck` passes

Create the PromoCard component with two visual formats (standard and compact) and its test suite.

## File: `ui/PromoCard.tsx`

```tsx
import { useState } from 'react';
import { motion } from 'motion/react';
import { ArrowRight, X } from 'lucide-react';
import { cn } from '@/layers/shared/lib';
import { useAppStore } from '@/layers/shared/model';
import type { PromoDefinition, PromoPlacement } from '../model/promo-types';
import { PromoDialog } from './PromoDialog';

const staggerItem = {
  initial: { opacity: 0, y: 12 },
  animate: { opacity: 1, y: 0 },
  exit: { opacity: 0, scale: 0.95, transition: { duration: 0.15 } },
} as const;

interface PromoCardProps {
  promo: PromoDefinition;
  placement: PromoPlacement;
}

/**
 * Individual promo card — renders in standard or compact format
 * based on the placement slot.
 */
export function PromoCard({ promo, placement }: PromoCardProps) {
  const dismissPromo = useAppStore((s) => s.dismissPromo);
  const [dialogOpen, setDialogOpen] = useState(false);
  const isCompact = placement === 'dashboard-sidebar' || placement === 'agent-sidebar';
  const Icon = promo.content.icon;

  const handleClick = () => {
    if (promo.action.type === 'dialog') {
      setDialogOpen(true);
    } else if (promo.action.type === 'navigate') {
      // Navigate using window.location or router
      window.location.href = promo.action.to;
    } else if (promo.action.type === 'action') {
      promo.action.handler();
    }
  };

  if (isCompact) {
    return (
      <motion.div variants={staggerItem} layout>
        <button
          data-slot="promo-card-compact"
          onClick={handleClick}
          className="flex w-full items-center gap-3 rounded-lg border border-border bg-card px-3 py-2.5 text-left transition-colors hover:bg-accent"
        >
          <div className="flex size-8 shrink-0 items-center justify-center rounded-md bg-muted">
            <Icon className="size-4 text-muted-foreground" />
          </div>
          <div className="min-w-0 flex-1">
            <p className="text-xs font-medium truncate">{promo.content.title}</p>
            <p className="text-[11px] text-muted-foreground truncate">{promo.content.shortDescription}</p>
          </div>
          <ArrowRight className="size-3.5 shrink-0 text-muted-foreground" />
        </button>
        {promo.action.type === 'dialog' && (
          <PromoDialog promo={promo} open={dialogOpen} onOpenChange={setDialogOpen} />
        )}
      </motion.div>
    );
  }

  // Standard format (dashboard-main)
  return (
    <motion.div variants={staggerItem} layout>
      <button
        data-slot="promo-card"
        onClick={handleClick}
        className="relative w-full rounded-xl border border-border bg-card p-6 text-left transition-colors hover:bg-accent"
      >
        {/* Dismiss button */}
        <button
          aria-label="Dismiss suggestion"
          onClick={(e) => {
            e.stopPropagation();
            dismissPromo(promo.id);
          }}
          className="absolute top-3 right-3 rounded-sm p-1 text-muted-foreground opacity-0 transition-opacity hover:text-foreground group-hover:opacity-100 hover:opacity-100 focus-visible:opacity-100"
        >
          <X className="size-3.5" />
        </button>

        <div className="flex size-9 items-center justify-center rounded-md bg-gradient-to-br from-muted to-muted/50">
          <Icon className="size-5 text-muted-foreground" />
        </div>
        <p className="mt-3 text-sm font-medium">{promo.content.title}</p>
        <p className="mt-1 text-sm text-muted-foreground line-clamp-2">{promo.content.shortDescription}</p>
        <span className="mt-3 inline-flex items-center gap-1 text-xs font-medium text-muted-foreground">
          {promo.content.ctaLabel}
          <ArrowRight className="size-3" />
        </span>
      </button>
      {promo.action.type === 'dialog' && (
        <PromoDialog promo={promo} open={dialogOpen} onOpenChange={setDialogOpen} />
      )}
    </motion.div>
  );
}
```

Note: The outer button for standard format should use `role="group"` and the `group` className for the dismiss button hover reveal pattern. Adjust as needed to ensure the dismiss X button only appears on card hover.

