import { AnimatePresence, motion, useReducedMotion } from 'motion/react';
import type { PromoPlacement } from '../model/promo-types';
import { usePromoSlot } from '../model/use-promo-slot';
import { PromoCard } from './PromoCard';

const sectionEntrance = {
  initial: { height: 0, opacity: 0 },
  animate: { height: 'auto', opacity: 1 },
  exit: { height: 0, opacity: 0 },
  transition: { duration: 0.2, ease: [0, 0, 0.2, 1] },
} as const;

const staggerContainer = {
  animate: { transition: { staggerChildren: 0.04 } },
} as const;

interface PromoSlotProps {
  /** Which placement slot to render. */
  placement: PromoPlacement;
  /** Maximum number of promo cards to show. */
  maxUnits: number;
}

/**
 * Renders promo cards for a given placement slot.
 * Zero DOM when no promos qualify. Layout varies by placement.
 */
export function PromoSlot({ placement, maxUnits }: PromoSlotProps) {
  const promos = usePromoSlot(placement, maxUnits);
  const shouldReduceMotion = useReducedMotion();

  const motionProps = shouldReduceMotion
    ? {}
    : sectionEntrance;

  return (
    <AnimatePresence initial={false}>
      {promos.length > 0 && (
        <motion.section
          key="promo-slot"
          data-slot="promo-slot"
          {...motionProps}
          className="overflow-hidden"
        >
          {placement === 'dashboard-main' && (
            <h2 className="mb-3 text-xs font-medium tracking-widest uppercase text-muted-foreground">
              Discover
            </h2>
          )}

          <motion.div
            variants={shouldReduceMotion ? undefined : staggerContainer}
            initial="initial"
            animate="animate"
            className={
              placement === 'dashboard-main'
                ? 'grid grid-cols-1 gap-3 sm:grid-cols-2'
                : 'space-y-2'
            }
          >
            {promos.map((promo) => (
              <PromoCard key={promo.id} promo={promo} placement={placement} />
            ))}
          </motion.div>
        </motion.section>
      )}
    </AnimatePresence>
  );
}
```

## Layout Variations by Placement

- `dashboard-main`: Section header ("DISCOVER" in `text-xs font-medium tracking-widest uppercase text-muted-foreground`) + responsive grid (1 col mobile, 2 col desktop, `gap-3`)
- `dashboard-sidebar` and `agent-sidebar`: Vertical stack with `space-y-2`, no section header

## Animation Details

- Section uses `motion.section` with locally-defined `sectionEntrance` variant (fade + height, 200ms duration, cubic-bezier ease)
- `staggerContainer` on the grid/stack for 40ms child stagger intervals
- All animations respect `useReducedMotion()` — when reduced motion is preferred, animations are omitted
- Uses `AnimatePresence` for enter/exit transitions, matching the NeedsAttentionSection pattern

